CREATE TABLE fact_sales (
    CustomerKey INT,
    ProductKey INT,
    SalesAmount FLOAT,
    TotalProductCost FLOAT,
    Profit FLOAT
)
WITH (
    DISTRIBUTION = HASH(CustomerKey),
    CLUSTERED COLUMNSTORE INDEX
);




DROP TABLE fact_sales;

CREATE TABLE fact_sales (
    CustomerKey INT,
    ProductKey INT,
    SalesAmount FLOAT,
    TotalProductCost FLOAT,
    Profit FLOAT
)
WITH (
    DISTRIBUTION = HASH(CustomerKey),
    CLUSTERED COLUMNSTORE INDEX
);

COPY INTO fact_sales
FROM 'https://aniket001.dfs.core.windows.net/synapse-container/silver/retailmart/sales_enriched/'
WITH (
    FILE_TYPE = 'PARQUET'
);


SELECT TOP 10 * 
FROM fact_sales;

SELECT COUNT(*) AS TotalRows
FROM fact_sales;

CREATE STATISTICS stat_sales_CustomerKey 
ON fact_sales(CustomerKey);

CREATE STATISTICS stat_sales_ProductKey 
ON fact_sales(ProductKey);

SELECT TOP 10
    CustomerKey,
    SUM(SalesAmount) AS TotalRevenue,
    SUM(Profit) AS TotalProfit
FROM fact_sales
GROUP BY CustomerKey
ORDER BY TotalRevenue DESC;

SELECT *
FROM OPENROWSET(
    BULK 'https://aniket001.dfs.core.windows.net/synapse-container/silver/retailmart/sales_enriched/',
    FORMAT = 'PARQUET'
) AS rows;
